arguments.new_str:
using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Breaking change 1: EF 9 renamed "Discriminator" to "$type".
            // Existing documents still use "Discriminator", so pin the old name.
            entity.HasDiscriminator<string>("Discriminator");

            // Breaking change 2: EF 9 changed id format from "EntityType|Key" to just "Key".
            // Existing documents use "Blog|<key>", so opt back into the legacy format.
            entity.HasPartitionKey(b => b.Id);
            entity.Property(b => b.Id)
                  .ToJsonProperty("id")
                  .HasValueGenerator<LegacyCosmosIdGenerator>();

            // Breaking change 3: EF 9 drops HasIndex for Cosmos (indexes are managed by Cosmos itself).
            // Removed the HasIndex call that was here — it now throws at runtime.
        });
    }
}

// Value generator that preserves the legacy "Blog|{key}" id format used by EF Core 8.
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class LegacyCosmosIdGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;
    public override string Next(EntityEntry entry) =>
        $"{entry.Metadata.ShortName()}|{Guid.NewGuid()}";
}

class Blog { public string Id { get; set; } public string Name { get; set; } }

