class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Breaking change 1: EF 9 renamed the discriminator property from
            // "Discriminator" to "$type". Existing documents and raw SQL queries
            // (e.g. WHERE c.Discriminator = 'Blog') use the old name — pin it.
            entity.HasDiscriminator<string>("Discriminator");

            // Breaking change 2: EF 9 changed the id format from "EntityType|Key"
            // to just "Key". Existing documents have id = "Blog|<key>", so generate
            // new ids in the same legacy format and read existing ones as-is.
            entity.Property(b => b.Id)
                  .ToJsonProperty("id")
                  .HasValueGenerator<LegacyCosmosIdGenerator>();

            // Breaking change 3: HasIndex() now throws for the Cosmos provider.
            // Cosmos manages indexes via indexing policy, not EF model config.
            // REMOVED: entity.HasIndex(b => b.Name);
        });
    }
}

