toolArgs.old_str:
class SyncJob
{
    void Run(BlogContext context)
    {
        // Breaking change 4: EF 9 enables sync-over-async tracking protection.
        // ToList() on a Cosmos DbSet now throws by default.
        // Fix: use async APIs (preferred) or disable the guard per-context.
        context.Database.AutoTransactionBehavior =
            Microsoft.EntityFrameworkCore.AutoTransactionBehavior.Never;

        var blogs = context.Blogs.ToList();
        foreach (var b in blogs) { b.Name = b.Name.Trim(); }
        context.SaveChanges();
    }

    // Preferred async alternative:
    async Task RunAsync(BlogContext context)
    {
        var blogs = await context.Blogs.ToListAsync();
        foreach (var b in blogs) { b.Name = b.Name.Trim(); }
        await context.SaveChangesAsync();
    }
}

toolArgs.new_str:
using Microsoft.EntityFrameworkCore;

class SyncJob
{
    // Breaking change 4: The Cosmos provider in EF 9 throws
    // InvalidOperationException on synchronous I/O by default.
    // Fix: convert to async (preferred).
    async Task RunAsync(BlogContext context)
    {
        var blogs = await context.Blogs.ToListAsync();
        foreach (var b in blogs) { b.Name = b.Name.Trim(); }
        await context.SaveChangesAsync();
    }
}

